// ─────────────────────────────────────────────────────────────────
// PATCH for CartPage.jsx  —  two changes only, everything else unchanged
// ─────────────────────────────────────────────────────────────────

// ── CHANGE 1 ──────────────────────────────────────────────────────
// Add this function directly BELOW the existing callUpdateCart function
// and ABOVE the existing placeOrder function.
//
// It fires one "remove" call per unit of every item so the server map
// fully empties (the server splices an entry when its qty reaches 0).

async function clearServerCart(cartItems) {
  await Promise.allSettled(
    cartItems.flatMap(item =>
      Array.from({ length: item.quantity }, () =>
        callUpdateCart({
          dish_id:    item.dish_id,
          dish_name:  item.dish_name,
          res_name:   item.res_name,
          res_id:     item.res_id,
          dish_image: item.dish_image,
          action:     "remove",
        })
      )
    )
  );
}


// ── CHANGE 2 ──────────────────────────────────────────────────────
// Replace the existing handleCheckout function inside CartPage() with this.
// The only new line is the clearServerCart call before dispatch(clearCart()).

  const handleCheckout = async () => {
    if (checkoutState === "loading") return;
